import React from "react";
import InfoPageLayout from "./InfoPageLayout";

const pageData = {
  title: "Security",
  subtitle: "Enterprise-grade security practices that protect your data. Learn how CyberVault keeps your infrastructure safe.",
  sections: [
    {
      title: "Our Security Principles",
      description: "Security is at the core of everything we do. Our platform is built on fundamental security principles.",
      grid: true,
      gridClass: "info-grid-2",
      grid: [
        {
          title: "Zero-Trust Architecture",
          description: "Every request is verified, authenticated, and authorized. We never trust, always verify - even for internal systems."
        },
        {
          title: "Defense in Depth",
          description: "Multiple layers of security controls ensure that even if one layer is breached, others provide protection."
        },
        {
          title: "Least Privilege",
          description: "Users and systems get only the minimum access needed to perform their functions, reducing attack surface."
        },
        {
          title: "Continuous Monitoring",
          description: "Real-time monitoring and automated threat detection ensure we catch anomalies as they happen."
        }
      ]
    },
    {
      title: "Infrastructure Security",
      description: "Our cloud infrastructure is protected by industry-leading security measures.",
      bgColor: "#f8fafc",
      grid: true,
      gridClass: "info-grid-3",
      grid: [
        {
          title: "Encryption at Rest",
          description: "All data is encrypted using AES-256 encryption when stored. We use customer-managed keys for additional control."
        },
        {
          title: "Encryption in Transit",
          description: "All data in transit is protected with TLS 1.3. We support perfect forward secrecy for additional protection."
        },
        {
          title: "Network Segmentation",
          description: "Production networks are isolated from other environments. Strict firewall rules control all traffic."
        },
        {
          title: "DDoS Protection",
          description: "Multi-layer DDoS protection mitigates attacks before they reach our infrastructure."
        },
        {
          title: "Intrusion Detection",
          description: "24/7 IDS monitoring detects and alerts on suspicious network activity in real-time."
        },
        {
          title: "Backup & Recovery",
          description: "Automated backups with tested recovery procedures ensure business continuity."
        }
      ]
    },
    {
      title: "Compliance Certifications",
      description: "We maintain rigorous compliance with industry standards.",
      grid: true,
      gridClass: "info-grid-4",
      grid: [
        { title: "SOC 2 Type II", description: "Annual audits verify security, availability, and confidentiality controls." },
        { title: "ISO 27001", description: "Certified information security management system (ISMS)." },
        { title: "GDPR Compliant", description: "Full compliance with EU data protection regulations." },
        { title: "HIPAA Compliant", description: "Healthcare data protection standards for sensitive information." }
      ]
    },
    {
      title: "Vulnerability Management",
      description: "Proactive identification and remediation of security vulnerabilities.",
      grid: true,
      gridClass: "info-grid-2",
      grid: [
        {
          title: "Continuous Scanning",
          description: "Automated vulnerability scans run continuously across our infrastructure."
        },
        {
          title: "Penetration Testing",
          description: "Regular third-party penetration testing by leading security firms."
        },
        {
          title: "Bug Bounty",
          description: "Responsible disclosure program rewards researchers for finding vulnerabilities."
        },
        {
          title: "Security Updates",
          description: "Critical patches applied within 24 hours. Regular maintenance windows for updates."
        }
      ]
    }
  ],
  color: "#8b5cf6"
};

function Security() {
  return <InfoPageLayout {...pageData} />;
}

export default Security;
